            ips.choose(&mut rand::thread_rng()).copied()
        }
    }
}

pub fn downcast<T: Read + Write + Unpin + 'static>(self) -> Result<Parts<T>, Self> {
    let (io, buf) = self.io.into_inner();
    match io.__hyper_downcast() {
        Ok(t) => Ok(Parts {
            io: *t,
            read_buf: buf,
        }),
        Err(io) => Err(Upgraded {
            io: Rewind::new_buffered(io, buf),
        }),
    }
}

pub(crate) fn now_or_never<F: std::future::Future>(fut: F) -> Option<F::Output> {
    let waker = noop_waker();
    let mut cx = Context::from_waker(&waker);
    // TODO: replace with std::pin::pin! once MSRV >= 1.68
    tokio::pin!(fut);
    match fut.poll(&mut cx) {
        Poll::Ready(res) => Some(res),
        Poll::Pending => None,
    }
}

pub fn retrieve_less_version(less_path: &dyn AsRef<OsStr>) -> Option<LessVersion> {
    let resolved_path = grep_cli::resolve_binary(less_path.as_ref()).ok()?;

    let cmd = Command::new(resolved_path).arg("--version").output().ok()?;
    if cmd.status.success() {
        parse_less_version(&cmd.stdout)
    } else {
        parse_less_version_busybox(&cmd.stderr)
    }
}

fn inspect_content_type(first_line: &[u8]) -> Option<ContentType> {
    if first_line.is_empty() {
        return None;
    }

    let content_type = content_inspector::inspect(first_line);
    if content_type == ContentType::UTF_8 && has_zip_signature(first_line) {
        Some(ContentType::BINARY)
    } else {
        Some(content_type)
    }
}

pub fn load_from_folder(path: &Path) -> Result<Option<Self>> {
    match Self::try_load_from_folder(path) {
        Ok(metadata) => Ok(Some(metadata)),
        Err(e) => {
            if let Error::SerdeYamlError(_) = e {
                Err(e)
            } else if path.join("syntaxes.bin").exists() || path.join("themes.bin").exists() {
                Ok(Some(Self::default()))
            } else {
                Ok(None)
            }
        }
    }
}

pub(super) fn transition_to_terminal(&self, count: usize) -> bool {
    let prev = Snapshot(self.val.fetch_sub(count * REF_ONE, AcqRel));
    assert!(
        prev.ref_count() >= count,
        "current: {}, sub: {}",
        prev.ref_count(),
        count
    );
    prev.ref_count() == count
}

pub async fn write(
  self: Rc<Self>,
  data: &[u8],
) -> Result<usize, std::io::Error> {
  use tokio::io::AsyncWriteExt;

  let mut wr = RcRef::map(&self, |r| &r.wr).borrow_mut().await;
  let nwritten = wr.write(data).await?;
  wr.flush().await?;
  Ok(nwritten)
}

