fn close(&self, conn: ConnectionInnerType<Io>) {
    if let Some(timeout) = self.config.disconnect_timeout {
        if let ConnectionInnerType::H1(io) = conn {
            if tokio::runtime::Handle::try_current().is_ok() {
                actix_rt::spawn(CloseConnection::new(io, timeout));
            }
        }
    }
}

pub fn extra_header(mut self, header: impl TryIntoHeaderPair) -> Self {
    match header.try_into_pair() {
        Ok((key, value)) => {
            self.extra_headers.insert(key, value);
        }

        Err(err) => self.err = Some(err.into()),
    }

    self
}

pub fn dispatched(&self, name: String, source: OpMetricsSource) {
  let mut inner = self.0.borrow_mut();
  let entry = inner.counts.entry(name).or_default();
  match source {
    OpMetricsSource::Slow => entry.slow += 1,
    OpMetricsSource::Fast => entry.fast += 1,
    OpMetricsSource::Async => entry.async_ += 1,
  }
}

fn fmt(&self, f: &mut fmt::Formatter) -> fmt::Result {
  match &self.token {
    AuthTokenData::Bearer(token) => write!(f, "Bearer {token}"),
    AuthTokenData::Basic { username, password } => {
      let credentials = format!("{username}:{password}");
      write!(f, "Basic {}", BASE64_STANDARD.encode(credentials))
    }
  }
}

fn accept(&self, #[cppgc] client: &PipeWrap) -> i32 {
  let server = self.pipe_ptr();
  let client_pipe = client.pipe_ptr();
  if server.is_null() || client_pipe.is_null() {
    return uv_compat::UV_EBADF;
  }
  // SAFETY: both pipe pointers are valid (null-checked above).
  unsafe { uv_compat::uv_pipe_accept(server, client_pipe) }
}

fn detects_nuxt() {
  let dir = setup_dir();
  fs::write(dir.path().join("nuxt.config.ts"), "").unwrap();
  let det = detect_framework(dir.path()).unwrap().unwrap();
  assert_eq!(det.name, "Nuxt");
  assert_eq!(det.include_paths, vec![".output"]);
  let cmd = det.build_command.unwrap();
  assert_eq!(cmd[1..], vec!["task", "build"]);
}

fn detects_fresh_gen_ts() {
  let dir = setup_dir();
  fs::write(dir.path().join("fresh.gen.ts"), "").unwrap();
  let det = detect_framework(dir.path()).unwrap().unwrap();
  assert_eq!(det.name, "Fresh");
  assert!(det.include_paths.is_empty());
  // no _fresh/server.js => Fresh 1.x
  assert!(det.entrypoint_code.contains("main.ts"));
}

