fn seq_bounded(cap: usize) {
    let (mut tx, rx) = mpsc::channel(cap);
    block_on(async {
        for i in 0..MESSAGES {
            tx.try_send(message::new(i)).unwrap();
        }
        drop(tx);

        rx.for_each(|_| future::ready(())).await
    });
}

